pragma solidity ^0.8.1;

contract VotingSystem {
    struct Candidate {
        uint voteCount;
    }

    mapping(uint => Candidate) public candidates;
    mapping(address => bool) public voters;

    uint public candidateCount;
    address public admin;
    bool public votingOpen;

    event CandidateRegistered(uint indexed id);
    event VoteCast(address indexed voter, uint indexed candidateId);
    event VotingEnded();

    constructor() {
        admin = msg.sender;
        votingOpen = true;
    }

    function registerCandidate() public {
        require(msg.sender == admin, "Only the admin can register a candidate");
        uint id = candidateCount++;
        candidates[id] = Candidate({voteCount: 0});
        emit CandidateRegistered(id);
    }

    function vote(uint _candidateId) public {
        require(voters[msg.sender] == false, "One vote per address");
        require(_candidateExists(_candidateId), "Candidate does not exist");
        require(votingOpen, "Voting is closed");

        voters[msg.sender] = true;
        candidates[_candidateId].voteCount++;

        emit VoteCast(msg.sender, _candidateId);
    }

    function endVoting() public {
        require(msg.sender == admin, "Only the admin can end voting");
        votingOpen = false;

        emit VotingEnded();
    }

    function winner() public view returns (uint) {
        uint winningCandidateId = 0;
        for (uint i=1; i<candidateCount; i++) {
            if(candidates[i].voteCount > candidates[winningCandidateId].voteCount){
                winningCandidateId = i;
            }
        }

        return winningCandidateId;
    }

    function _candidateExists(uint _candidateId) internal view returns (bool) {
        if(_candidateId >= candidateCount) {
            return false;
        }

        return true;
    }
}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.1;

contract Escrow {
    address payable public buyer;
    address payable public seller;
    address payable public arbiter;

    enum State { Created, Delivered, Released, Refunded, Disputed }
    State private state;

    constructor(address payable _buyer, address payable _seller, address payable _arbiter) {
        require(_buyer != address(0), "Invalid buyer address");
        require(_seller != address(0), "Invalid seller address");
        require(_arbiter != address(0), "Invalid arbiter address");

        buyer = _buyer;
        seller = _seller;
        arbiter = _arbiter;
    }

    function deposit() public payable {
        require(msg.value > 0, "Deposit must be greater than 0");
        require(state == State.Created, "Invalid state for deposit");

        buyer.transfer(msg.value);
        state = State.Delivered;
    }

    function markAsDelivered() public {
        require(msg.sender == seller, "Only the seller can mark as delivered");
        require(state == State.Delivered, "Invalid state for marking as delivered");

        state = State.Released;
    }

    function releasePayment() public {
        require(msg.sender == buyer, "Only the buyer can release payment");
        require(state == State.Released, "Invalid state for releasing payment");

        payable(seller).transfer(address(this).balance);
        state = State.Refunded;
    }

    function dispute() public {
        require(msg.sender == arbiter, "Only the arbiter can dispute");
        require(state == State.Released || state == State.Disputed, "Invalid state for disputing");

        if (state == State.Released) {
            state = State.Disputed;
        } else {
            revert("Cannot dispute after arbiter decision");
        }
    }

    function arbitrate(bool buyerWins) public {
        require(msg.sender == arbiter, "Only the arbiter can arbitrate");
        require(state == State.Disputed, "Invalid state for arbitrating");

        if (buyerWins) {
            payable(buyer).transfer(address(this).balance);
        } else {
            payable(seller).transfer(address(this).balance);
        }

        state = State.Refunded;
    }

    function getState() public view returns (State) {
        return state;
    }
}

