pragma solidity ^0.8.1;

contract Escrow {
    address payable public buyer;
    address payable public seller;
    address payable public arbiter;

    enum State { Created, Delivered, Released, Refunded, Disputed }
    State public state;

    constructor(address payable _buyer, address payable _seller, address payable _arbiter) {
        require(_buyer != address(0), "Invalid buyer address");
        require(_seller != address(0), "Invalid seller address");
        require(_arbiter != address(0), "Invalid arbiter address");

        buyer = _buyer;
        seller = _seller;
        arbiter = _arbiter;

        state = State.Created;
    }

    function deposit() public payable {
        require(msg.value > 0, "Deposit must be greater than 0");
        require(state == State.Created, "Invalid contract state for deposit");

        if (msg.sender != buyer) {
            revert("Only the buyer can deposit funds");
        }
    }

    function markAsDelivered() public {
        require(state == State.Created, "Invalid contract state for delivery");
        require(msg.sender == seller, "Only the seller can mark as delivered");

        state = State.Delivered;
    }

    function releasePayment() public {
        require(state == State.Disputed || state == State.Released, 
                "Invalid contract state for payment release");

        if (msg.sender == seller) {
            payable(buyer).transfer(address(this).balance);
            state = State.Refunded;
        } else if (msg.sender == buyer) {
            require(state != State.Released, "Payment has already been released");

            state = State.Released;
            payable(seller).transfer(address(this).balance);
        } else {
            revert("Only the buyer or seller can release funds");
        }
    }

    function dispute() public {
        require(state == State.Delivered, "Invalid contract state for dispute");

        if (msg.sender != arbiter) {
            revert("Only the arbiter can resolve disputes");
        }

        state = State.Disputed;
    }
}

