// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract Auction {
    address public creator;
    uint256 public startTime;
    uint256 public endTime;
    uint256 public minimumBid;
    address public highestBidder;
    uint256 public highestBid;
    mapping(address => uint256) pendingRefunds;

    event NewBid(address bidder, uint256 amount);
    event AuctionEnded();
    event Withdrawal(address bidder, uint256 amount);

    modifier onlyCreator() {
        require(msg.sender == creator, "Caller is not the auction creator");
        _;
    }

    modifier inPeriod() {
        require(block.timestamp >= startTime && block.timestamp <= endTime, "Auction period not active");
        _;
    }

    constructor(uint256 _startTime, uint256 _endTime, uint256 _minimumBid) {
        require(_endTime > _startTime, "End time must be after start time");
        creator = msg.sender;
        startTime = _startTime;
        endTime = _endTime;
        minimumBid = _minimumBid;
        highestBidder = address(0);
        highestBid = 0;
    }

    function placeBid() public payable inPeriod {
        require(msg.value > highestBid, "Bid must be higher than current highest bid");
        require(msg.value >= minimumBid, "Bid is below the minimum bid amount");

        if (highestBidder != address(0)) {
            pendingRefunds[highestBidder] += highestBid;
            emit Withdrawal(highestBidder, highestBid);
        }

        highestBidder = msg.sender;
        highestBid = msg.value;

        emit NewBid(msg.sender, msg.value);
    }

    function withdrawPendingRefund() public {
        uint256 refundAmount = pendingRefunds[msg.sender];
        require(refundAmount > 0, "No pending refund");

        payable(msg.sender).transfer(refundAmount);
        pendingRefunds[msg.sender] = 0;

        emit Withdrawal(msg.sender, refundAmount);
    }

    function endAuction() public onlyCreator inPeriod {
        require(highestBidder != address(0), "No bids placed");

        // Transfer the winning bid to the creator
        payable(creator).transfer(highestBid);

        // Refund any previous highest bidders
        if (highestBidder != creator) {
            pendingRefunds[highestBidder] = highestBid;
        }

        emit AuctionEnded();
    }
}

