        require(state == State.Delivered, "Cannot release payment");
        state = State.Released;
        payable(seller).transfer(address(this).balance);
        emit Released();
    }

    function dispute() external {
        require(state == State.Created || state == State.Delivered, "Cannot dispute in current state");
        require(msg.sender == buyer || msg.sender == seller, "Only buyer or seller can dispute");
        state = State.Disputed;
        emit Disputed();
    }

    function resolveDispute(bool refundToBuyer) external {
        require(msg.sender == arbiter, "Only arbiter can resolve disputes");
        require(state == State.Disputed, "Cannot resolve dispute in current state");
        if (refundToBuyer) {
            payable(buyer).transfer(address(this).balance);
            state = State.Refunded;
            emit Refunded();
        } else {
            payable(seller).transfer(address(this).balance);
            state = State.Released;
            emit Released();
        }
    }
}

