contract Voting {
    struct Candidate {
        string name;
        uint voteCount;
    }

    mapping(uint => Candidate) public candidates;
    uint public candidateCount;
    mapping(address => bool) public voters;
    bool public votingEnded;
    address public admin;

    event CandidateRegistered(uint id, string name);
    event VoteCast(address voter, uint candidateId);
    event VotingEnded(uint winningCandidateId);

    constructor() {
        admin = msg.sender;
    }

    function registerCandidate(string memory _name) public {
        require(msg.sender == admin, "Only admin can register candidates");
        candidateCount++;
        candidates[candidateCount] = Candidate(_name, 0);
        emit CandidateRegistered(candidateCount, _name);
    }

    function vote(uint _candidateId) public {
        require(!votingEnded, "Voting has ended");
        require(_candidateId > 0 && _candidateId <= candidateCount, "Invalid candidate ID");
        require(!voters[msg.sender], "You have already voted");

        candidates[_candidateId].voteCount++;
        voters[msg.sender] = true;
        emit VoteCast(msg.sender, _candidateId);
    }

    function endVoting() public {
        require(msg.sender == admin, "Only admin can end voting");
        require(!votingEnded, "Voting already ended");

        votingEnded = true;
        uint winningCandidateId = 0;
        uint maxVotes = 0;

        for (uint i = 1; i <= candidateCount; i++) {
            if (candidates[i].voteCount > maxVotes) {
                maxVotes = candidates[i].voteCount;
                winningCandidateId = i;
            }
        }

        emit VotingEnded(winningCandidateId);
    }

    function getWinningCandidate() public view returns (uint) {
        require(votingEnded, "Voting has not ended yet");
        uint winningCandidateId = 0;
        uint maxVotes = 0;

        for (uint i = 1; i <= candidateCount; i++) {
            if (candidates[i].voteCount > maxVotes) {
                maxVotes = candidates[i].voteCount;
                winningCandidateId = i;
            }
        }

        return winningCandidateId;
    }
}

