pragma solidity ^0.8.20;

contract SimpleVoting {
    address public owner;
    bool public votingEnded = false;
    uint256 public winnerCandidateId;

    mapping(uint256 => uint256) private votes;
    mapping(uint256 => bool) private candidateExists;
    uint256[] private candidateIds;

    mapping(address => bool) private hasVoted;

    event CandidateRegistered(uint256 indexed candidateId);
    event VoteCast(address indexed voter, uint256 indexed candidateId);
    event VotingEnded(uint256 indexed winnerCandidateId);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not admin");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function registerCandidate(uint256 _candidateId) external onlyOwner {
        require(!votingEnded, "Voting ended");
        require(!candidateExists[_candidateId], "Already registered");
        candidateExists[_candidateId] = true;
        candidateIds.push(_candidateId);
        emit CandidateRegistered(_candidateId);
    }

    function vote(uint256 _candidateId) external {
        require(!votingEnded, "Voting ended");
        require(msg.sender != owner, "Admin cannot vote");
        require(candidateExists[_candidateId], "Candidate does not exist");
        require(!hasVoted[msg.sender], "Already voted");

        hasVoted[msg.sender] = true;
        votes[_candidateId] += 1;

        emit VoteCast(msg.sender, _candidateId);
    }

    function endVoting() external onlyOwner {
        require(!votingEnded, "Already ended");
        require(candidateIds.length > 0, "No candidates");

        votingEnded = true;

        uint256 maxVotes = 0;
        uint256 winningCandidate = candidateIds[0];
        for (uint256 i = 0; i < candidateIds.length; i++) {
            uint256 cid = candidateIds[i];
            uint256 v = votes[cid];
            if (v > maxVotes) {
                maxVotes = v;
                winningCandidate = cid;
            }
        }

        winnerCandidateId = winningCandidate;
        emit VotingEnded(winningCandidate);
    }

    function getWinner() external view returns (uint256) {
        require(votingEnded, "Voting not ended");
        return winnerCandidateId;
    }

    function hasVotedBefore(address _voter) external view returns (bool) {
        return hasVoted[_voter];
    }

    function candidateVoteCount(uint256 _candidateId) external view returns (uint256) {
        require(candidateExists[_candidateId], "Candidate does not exist");
        return votes[_candidateId];
    }
}

