contract Escrow {
    address public immutable buyer;
    address public immutable seller;
    address public immutable arbiter;
    uint256 public immutable amount;
    enum State { Created, Delivered, Released, Refunded, Disputed }
    State public state;

    event EscrowCreated(address indexed buyer, address indexed seller, address indexed arbiter, uint256 amount);
    event ItemDelivered();
    event PaymentReleased();
    event FundsRefunded();
    event DisputeRaised();
    event DisputeResolved(bool releasedToSeller);

    modifier onlyBuyer() {
        require(msg.sender == buyer, "Not buyer");
        _;
    }

    modifier onlySeller() {
        require(msg.sender == seller, "Not seller");
        _;
    }

    modifier onlyArbiter() {
        require(msg.sender == arbiter, "Not arbiter");
        _;
    }

    uint256 private unlocked = 1;
    modifier nonReentrant() {
        require(unlocked == 1, "ReentrancyGuard: reentrant call");
        unlocked = 0;
        _;
        unlocked = 1;
    }

    constructor(address _buyer, address _seller, address _arbiter) payable {
        require(_buyer != address(0) && _seller != address(0) && _arbiter != address(0), "Zero address");
        require(_buyer != _seller && _buyer != _arbiter && _seller != _arbiter, "Addresses must be distinct");
        require(msg.sender == _buyer, "Only buyer can deploy");
        require(msg.value > 0, "Must deposit ether");

        buyer = _buyer;
        seller = _seller;
        arbiter = _arbiter;
        amount = msg.value;
        state = State.Created;

        emit EscrowCreated(buyer, seller, arbiter, amount);
    }

    function markDelivered() external onlySeller {
        require(state == State.Created, "Already delivered or finished");
        state = State.Delivered;
        emit ItemDelivered();
    }

    function releasePayment() external onlyBuyer nonReentrant {
        require(state == State.Delivered, "Not ready to release");
        state = State.Released;
        (bool sent, ) = seller.call{value: address(this).balance}("");
        require(sent, "Transfer failed");
        emit PaymentReleased();
    }

    function raiseDispute() external {
        require(msg.sender == buyer || msg.sender == seller, "Only parties can dispute");
        require(state == State.Delivered, "Cannot dispute now");
        state = State.Disputed;
        emit DisputeRaised();
    }

    function resolveDispute(bool releaseToSeller) external onlyArbiter nonReentrant {
        require(state == State.Disputed, "No dispute to resolve");
        if (releaseToSeller) {
            state = State.Released;
            (bool sent, ) = seller.call{value: address(this).balance}("");
            require(sent, "Transfer failed");
            emit DisputeResolved(true);
            emit PaymentReleased();
        } else {
            state = State.Refunded;
            (bool sent, ) = buyer.call{value: address(this).balance}("");
            require(sent, "Transfer failed");
            emit DisputeResolved(false);
            emit FundsRefunded();
        }
    }
}

