// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

contract Auction {
    uint public startTime;
    uint public endTime;
    uint public minBidIncrement;

    address payable public highestBidder;
    uint public highestBid;

    bool public ended;

    mapping(address => uint) public bids;

    event AuctionStarted(uint startTime, uint endTime, uint minBidIncrement);
    event NewBid(address bidder, uint amount);
    event AuctionEnded(address winner, uint amount);
    event Withdrawal(address recipient, uint amount);

    constructor(uint _startTime, uint _endTime, uint _minBidIncrement) {
        require(_startTime > block.timestamp, "Auction must start in the future");
        require(_endTime > _startTime, "End time must be after start time");

        startTime = _startTime;
        endTime = _endTime;
        minBidIncrement = _minBidIncrement;
    }

    function bid() public payable {
        require(block.timestamp >= startTime && block.timestamp <= endTime, "Auction is not active");

        uint amount = msg.value + minBidIncrement;
        require(amount > highestBid, "Your bid must be higher than the current highest bid");

        if (highestBid > 0) {
            payable(highestBidder).transfer(highestBid);
        }

        bids[msg.sender] = amount;
        highestBidder = payable(msg.sender);
        highestBid = amount;

        emit NewBid(msg.sender, amount);
    }

    function endAuction() public {
        require(block.timestamp > endTime, "Auction is not over yet");
        require(!ended, "Auction has already ended");

        if (highestBid > 0) {
            payable(highestBidder).transfer(highestBid);
        }

        emit AuctionEnded(highestBidder, highestBid);
        ended = true;
    }

    function withdraw() public {
        require(ended, "Auction is not over yet");

        uint amount = bids[msg.sender];
        delete bids[msg.sender];

        payable(msg.sender).transfer(amount);

        emit Withdrawal(msg.sender, amount);
    }
}

