Task: Escrow Contract

Specification: Create a three-party escrow contract with dispute resolution.
Requirements:
- Initialize with buyer, seller, and arbiter addresses at deployment
- Buyer deposits exact Ether amount during contract creation (payable constructor)
- Seller can mark item as delivered
- Buyer can release payment to seller if satisfied
- Arbiter can resolve disputes and allocate funds to buyer or seller
- Track contract state (Created, Delivered, Released, Refunded, Disputed)
- Emit events for all state changes
- Ensure funds can only be released once using state checks
Security: Use Checks-Effects-Interactions pattern, prevent reentrancy, validate all addresses are unique and non-zero

Faulty Contract:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract Escrow {
    address public buyer;
    address public seller;
    address public arbiter;
    uint256 public itemPrice;
    string private constant STATE_CREATED = "Created";
    string private constant STATE_DELIVERED = "Delivered";
    string private constant STATE_RELEASED = "Released";
    string private constant STATE_REFUNDED = "Refunded";
    string private constant STATE_DISPUTED = "Disputed";
    string private state;

    event ItemPriceSet(uint256 price);
    event BuyerDeposited(address indexed buyer, uint256 amount);
    event SellerMarkedDelivered();
    event PaymentReleased(address indexed seller, uint256 amount);
    event RefundIssued(address indexed buyer, uint256 amount);
    event DisputeResolved(address indexed winner, uint256 amount);

    constructor(
        address _buyer,
        address _seller,
        address _arbiter,
        uint256 _itemPrice
    ) payable {
        require(_buyer != address(0), "Buyer must be a non-zero address");
        require(_seller != address(0), "Seller must be a non-zero address");
        require(_arbiter != address(0), "Arbiter must be a non-zero address");
        require(_buyer != _seller, "Buyer and Seller cannot be the same address");
        require(_buyer != _arbiter, "Buyer and Arbiter cannot be the same address");
        require(_seller != _arbiter, "Seller and Arbiter cannot be the same address");

        buyer = _buyer;
        seller = _seller;
        arbiter = _arbiter;
        itemPrice = _itemPrice;

        state = STATE_CREATED;

        BuyerDeposited(buyer, msg.value);
    }

    function markDelivered() external {
        require(msg.sender == seller, "Only seller can mark item as delivered");
        require(state == STATE_CREATED, "Item must be in Created state to be marked delivered");

        state = STATE_DELIVERED;
        SellerMarkedDelivered();
    }

    function releasePayment() external {
        require(msg.sender == buyer, "Only buyer can release payment");
        require(state == STATE_DELIVERED, "Item must be in Delivered state to release payment");

        state = STATE_RELEASED;
        payable(seller).transfer(address(this).balance);
        PaymentReleased(seller, address(this).balance);

        // Reset contract for potential reuse
        selfdestruct(payable(buyer));
    }

    function refundPayment() external {
        require(msg.sender == buyer, "Only buyer can request a refund");
        require(state == STATE_CREATED || state == STATE_DELIVERED, "Refund only possible before or after delivery");

        state = STATE_REFUNDED;
        payable(buyer).transfer(address(this).balance);
        RefundIssued(buyer, address(this).balance);

        // Reset contract for potential reuse
        selfdestruct(payable(seller));
    }

    function dispute() external {
        require(msg.sender == buyer || msg.sender == seller, "Only buyer or seller can initiate a dispute");
        require(state == STATE_RELEASED, "Dispute only possible after payment release");

        state = STATE_DISPUTED;
    }

    function arbiterResolve(bool _isSellerWinner) external {
        require(msg.sender == arbiter, "Only arbiter can resolve disputes");
        require(state == STATE_DISPUTED, "Arbiter must resolve a Disputed state");

        if (_isSellerWinner) {
            state = STATE_RELEASED;
            payable(seller).transfer(address(this).balance);
            DisputeResolved(seller, address(this).balance);
        } else {
            state = STATE_REFUNDED;
            payable(buyer).transfer(address(this).balance);
            DisputeResolved(buyer, address(this).balance);
        }

        // Reset contract for potential reuse
        selfdestruct(payable(seller));
    }
}

