Task: Crowdfunding Contract

Specification: Create a goal-based crowdfunding campaign with refund mechanism.
Requirements:
- Set campaign creator, funding goal, and deadline at deployment
- Accept contributions only before deadline
- Track contributions per address using mapping
- Implement goal check (total contributions >= goal)
- Creator can withdraw funds only if goal reached after deadline
- Contributors can claim refunds only if goal not reached after deadline
- Prevent double refunds using state tracking
- Emit events for contributions, withdrawals, and refunds
Security: Use Checks-Effects-Interactions pattern, prevent reentrancy on refunds, validate deadline is in the future

Faulty Contract:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract Crowdfunding {
    address public creator;
    uint256 public goal;
    uint256 public deadline;
    mapping(address => uint256) public contributions;
    bool public goalReached;
    bool[] public refunded; // to prevent double refunds

    event Contribution(address indexed contributor, uint256 amount);
    event Withdrawal(uint256 amount);
    event Refund(address indexed contributor);

    constructor(uint256 _goal, uint256 _deadline) {
        require(_deadline > block.timestamp, "Deadline must be in the future");
        creator = msg.sender;
        goal = _goal;
        deadline = _deadline;
        goalReached = false;
    }

    function contribute() external payable {
        require(block.timestamp < deadline, "Contribution period has ended");
        require(!goalReached, "Goal already reached");

        contributions[msg.sender] += msg.value;
        emit Contribution(msg.sender, msg.value);

        if (contributionsTotal() >= goal) {
            goalReached = true;
        }
    }

    function contributionsTotal() internal view returns (uint256) {
        uint256 total = 0;
        for (address addr : allContributors()) {
            total += contributions[addr];
        }
        return total;
    }

    function withdrawFunds() external {
        require(msg.sender == creator, "Only creator can withdraw");
        require(goalReached, "Goal not reached");
        require(block.timestamp >= deadline, "Withdrawal before deadline");

        uint256 amount = contributionsTotal();
        payable(creator).transfer(amount);
        emit Withdrawal(amount);
    }

    function claimRefund() external {
        require(!goalReached, "Goal reached; no refunds");
        require(!refunded[msg.sender], "Already refunded");
        require(block.timestamp >= deadline, "Refund before deadline");

        uint256 refundAmount = contributions[msg.sender];
        contributions[msg.sender] = 0;
        refunded[msg.sender] = true;
        payable(msg.sender).transfer(refundAmount);
        emit Refund(msg.sender);
    }

    function allContributors() internal view returns (address[] memory) {
        // Solidity does not provide a direct way to iterate over mappings,
        // so we assume a reasonable maximum number of contributors.
        // In production, consider using a library or off-chain data for large numbers.
        return new address[](1000);
    }
}

