        // Check if the bid is higher than the current highest bid
        require(_amount > auction.highestBid, "Bid must be higher than current highest bid");

        // Update the highest bidder and bid amount
        auction.highestBidder = msg.sender;
        auction.highestBid = _amount;

        // Emit a new bid event
        emit NewBid(_auctionId, msg.sender, _amount);
    }

    function endAuction(uint256 _auctionId) public {
        // Get the auction details
        AuctionDetails storage auction = auctions[_auctionId];

        // Check if the auction has ended already
        require(!auction.ended, "Auction has already ended");

        // Set the auction as ended
        auction.ended = true;

        // Emit an auction end event
        emit AuctionEnded(_auctionId);
    }

    function withdraw(uint256 _auctionId) public {
        // Get the auction details
        AuctionDetails storage auction = auctions[_auctionId];

        // Check if the auction has ended and not already withdrawn
        require(auction.ended, "Auction has not ended yet");
        require(msg.sender == auction.highestBidder, "Only highest bidder can withdraw");

        // Transfer the winnings to the auction creator
        payable(address(this)).transfer(auction.highestBid);

        // Emit a withdrawal event
        emit Withdrawn(_auctionId, auction.highestBidder, auction.highestBid);
    }

    function manualWithdraw(uint256 _auctionId) public {
        // Get the auction details
        AuctionDetails storage auction = auctions[_auctionId];

        // Check if the auction has ended and not already withdrawn
        require(auction.ended, "Auction has not ended yet");

        // Transfer the winnings to the auction creator
        payable(address(this)).transfer(auction.highestBid);

        // Emit a withdrawal event
        emit Withdrawn(_auctionId, address(0), auction.highestBid);
    }
}

