Specification: Create a time-locked wallet contract with withdrawal restrictions.
Requirements:
- Accept Ether deposits from any address
- Store beneficiary address and unlock timestamp (both immutable, set at deployment)
- Implement withdrawal function restricted to beneficiary only
- Reject withdrawal attempts before unlock time with clear error message
- Emit events for deposits and withdrawals
- Use block.timestamp for time checks
Security: Ensure beneficiary cannot be zero address, validate unlock time is in the future

Faulty Contract:
pragma solidity ^0.8.23;

contract TimeLockedWallet {
    address public immutable beneficiary;
    uint256 public immutable unlockTime;
    uint256 private constant MIN_UNLOCK_DELTA = 1 days; // Minimum lock duration

    event Deposited(address indexed sender, uint256 amount);
    event Withdrawn(address indexed recipient, uint256 amount);

    constructor(
        address _beneficiary,
        uint256 _unlockTime
    ) {
        require(_beneficiary != address(0), "Beneficiary cannot be zero");
        require(block.timestamp < _unlockTime, "Unlock time must be in the future");
        require(_unlockTime - block.timestamp >= MIN_UNLOCK_DELTA, "Minimum lock duration violated");

        beneficiary = _beneficiary;
        unlockTime = _unlockTime;
    }

    receive() external payable {
        emit Deposited(msg.sender, msg.value);
    }

    function withdraw() external nonReentrant {
        require(msg.sender == beneficiary, "Only beneficiary can withdraw");
        require(block.timestamp >= unlockTime, "Withdrawal not yet available");

        uint256 amount = address(this).balance;
        payable(beneficiary).transfer(amount);
        emit Withdrawn(beneficiary, amount);
    }

    modifier nonReentrant() {
        static bool private _isWithdrawing;
        require(!_isWithdrawing, "Reentrancy attack detected");
        _isReentering = true;
        _;
        _isReentering = false;
    }
}

