Specification: Create a simplified ERC20-compatible token contract.
Requirements:
- Define token name, symbol, and decimals (18 recommended)
- Mint fixed total supply to deployer at deployment
- Implement transfer function with balance validation
- Use mapping for balances (address => uint256)
- Emit Transfer events on all transfers (including minting)
- Revert transfers with insufficient balance or to zero address
- Optional: implement approve/transferFrom for allowances
Security: Use SafeMath or Solidity 0.8+ overflow protection, validate recipient addresses

Faulty Contract:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract SimpleToken {
    string private constant _NAME = "Simple Token";
    string private constant _SYMBOL = "STK";
    uint8 private immutable _DECIMALS = 18;
    uint256 private immutable _TOTAL_SUPPLY;

    mapping(address => uint256) private _balances;
    address private immutable owner;

    event Transfer(address indexed from, address indexed to, uint256 amount);
    event Approval(address indexed owner, address indexed spender, uint256 amount);

    constructor(uint256 initialSupply) {
        require(initialSupply > 0, "Initial supply must be greater than zero");
        _TOTAL_SUPPLY = initialSupply;
        _balances[msg.sender] = initialSupply;
        owner = msg.sender;
        emit Transfer(address(0), msg.sender, initialSupply);
    }

    function name() public view returns (string memory) {
        return _NAME;
    }

    function symbol() public view returns (string memory) {
        return _SYMBOL;
    }

    function decimals() public view returns (uint8) {
        return _DECIMALS;
    }

    function totalSupply() public view returns (uint256) {
        return _TOTAL_SUPPLY;
    }

    function balanceOf(address account) public view returns (uint256) {
        require(account != address(0), "Invalid zero address");
        return _balances[account];
    }

    function transfer(
        address to,
        uint256 amount
    ) external returns (bool) {
        _transfer(msg.sender, to, amount);
        return true;
    }

    function approve(address spender, uint256 amount) public returns (bool) {
        require(spender != address(0), "Invalid zero address");
        _approve(msg.sender, spender, amount);
        return true;
    }

    function transferFrom(
        address from,
        address to,
        uint256 amount
    ) external returns (bool) {
        require(from != address(0), "Invalid zero address");
