// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract Escrow {
    enum State { Created, Delivered, Released, Refunded, Disputed }
    enum DisputeResult { BuyerWins, SellerWins }

    struct ContractState {
        address buyer;
        address seller;
        address arbiter;
        uint256 depositAmount;
        bool itemDelivered;
        State currentState;
        DisputeResult disputeResult;
    }

    ContractState public state;

    event StateChanged(address indexed buyer, address indexed seller, State previousState, State newState);
    event PaymentReleased(address indexed buyer, address indexed seller, uint256 amount);
    event Refunded(address indexed buyer, uint256 amount);
    event DisputeResolved(address indexed arbiter, DisputeResult result);

    constructor(
        address _buyer,
        address _seller,
        address _arbiter,
        uint256 _depositAmount
    ) payable {
        require(_buyer != address(0), "Buyer address cannot be zero");
        require(_seller != address(0), "Seller address cannot be zero");
        require(_arbiter != address(0), "Arbiter address cannot be zero");
        require(_buyer != _seller, "Buyer and seller must be different addresses");
        require(_buyer != _arbiter, "Buyer and arbiter must be different addresses");
        require(_seller != _arbiter, "Seller and arbiter must be different addresses");

        state = ContractState({
            buyer: _buyer,
            seller: _seller,
            arbiter: _arbiter,
            depositAmount: _depositAmount,
            itemDelivered: false,
            currentState: State.Created
        });

        require(address(this).balance == _depositAmount, "Incorrect deposit amount");
    }

    modifier onlyBuyer() {
        require(msg.sender == state.buyer, "Only buyer can call this function");
        _;
    }

    modifier onlySeller() {
        require(msg.sender == state.seller, "Only seller can call this function");
        _;
    }

    modifier onlyArbiter() {
        require(msg.sender == state.arbiter, "Only arbiter can call this function");
        _;
    }

    modifier validState(State requiredState) {
        require(state.currentState == requiredState, "Invalid contract state");
        _;
    }

    function markItemDelivered() external onlySeller validState(State.Created) {
        state.itemDelivered = true;
        state.currentState = State.Delivered;

        emit StateChanged(
            state.buyer,
            state.seller,
            State.Created,
            State.Delivered
        );
    }

    function releasePayment() external onlyBuyer validState(State.Delivered) {
        require(state.itemDelivered, "Item not delivered");

        payable(state.seller).transfer(state.depositAmount);
        state.currentState = State.Released;

        emit PaymentReleased(
            state.buyer,
            state.seller,
            state.depositAmount
        );
    }

    function dispute() external onlyBuyer validState(State.Delivered) {
        require(!state.itemDelivered, "Item already delivered");

        state.currentState = State.Disputed;

        emit StateChanged(
            state.buyer,
            state.seller,
            State.Delivered,
            State.Disputed
        );
    }

    function resolveDispute(DisputeResult result) external onlyArbiter validState(State.Disputed) {
        require(result == DisputeResult.BuyerWins || result == DisputeResult.SellerWins, "Invalid dispute result");

        state.disputeResult = result;
        state.currentState = (result == DisputeResult.BuyerWins)
            ? State.Refunded
            : State.Released;

        if (result == DisputeResult.BuyerWins) {
            payable(state.buyer).transfer(state.depositAmount);
            emit Refunded(
                state.buyer,
                state.depositAmount
            );
        } else {
            payable(state.seller).transfer(state.depositAmount);
            emit PaymentReleased(
                state.buyer,
                state.seller,
                state.depositAmount
            );
        }

        emit DisputeResolved(
            state.arbiter,
            result
        );
    }
}

