// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract SimpleVotingSystem {
    struct Candidate {
        string name;
        uint vote;
    }

    address public admin;
    uint public nextCandidateId;
    mapping(uint => Candidate) public candidates;
    mapping(address => bool) public voters;
    bool public votingEnded;
    uint[] public candidateIds;

    event CandidateRegistered(uint candidateId, string name);
    event VoteCast(address voter, uint candidateId);
    event VotingEnded();

    constructor(address _admin) {
        admin = _admin;
        nextCandidateId = 1;
    }

    function registerCandidate(string memory _name) public {
        require(msg.sender == admin, "Only admin can register candidates");
        require(!votingEnded, "Voting has already ended");
        candidates[nextCandidateId] = Candidate(_name, 0);
        candidateIds.push(nextCandidateId);
        emit CandidateRegistered(nextCandidateId, _name);
        nextCandidateId++;
    }

    function vote(uint _candidateId) public {
        require(!votingEnded, "Voting has ended");
        require(!voters[msg.sender], "Already voted");
        require(msg.sender != admin, "Admin cannot vote");
        require(candidates[_candidateId].name != "", "Candidate does not exist");
        candidates[_candidateId].vote++;
        voters[msg.sender] = true;
        emit VoteCast(msg.sender, _candidateId);
    }

    function endVoting() public {
        require(msg.sender == admin, "Only admin can end voting");
        require(!votingEnded, "Voting has already ended");
        votingEnded = true;
        emit VotingEnded();
    }

    function getWinner() public view returns (uint) {
        require(votingEnded, "Voting has not ended yet");
        uint maxVotes = 0;
        uint winnerId = 0;
        for (uint i = 0; i < candidateIds.length; i++) {
            uint candidateId = candidateIds[i];
            if (candidates[candidateId].vote > maxVotes) {
                maxVotes = candidates[candidateId].vote;
                winnerId = candidateId;
            }
        }
        return winnerId;
    }
}

