// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract MultiSigWallet {
    address[] public owners;
    uint256 public threshold;
    uint256 public transactionCount;
    mapping(uint256 => Transaction) public transactions;
    mapping(uint256 => mapping(address => bool)) public approvals;

    struct Transaction {
        address target;
        uint256 value;
        bytes data;
        uint256 status; // 0: pending, 1: executed, 2: canceled
    }

    event Submission(uint256 indexed txId, address indexed target, uint256 value, bytes data);
    event Approval(uint256 indexed txId, address indexed owner);
    event Execution(uint256 indexed txId, address indexed target, uint256 value, bytes data);

    constructor(address[] memory _owners, uint256 _threshold) {
        require(_owners.length > 0, "Owners cannot be empty");
        require(_threshold <= _owners.length, "Threshold exceeds number of owners");
        require(_threshold > 0, "Threshold must be positive");

        owners = _owners;
        threshold = _threshold;
    }

    function submitTransaction(address _target, uint256 _value, bytes memory _data) public {
        require(isOwner(msg.sender), "Only owners can submit transactions");
        require(_target != address(0), "Cannot send to zero address");

        transactionCount++;
        uint256 txId = transactionCount;

        transactions[txId] = Transaction({
            target: _target,
            value: _value,
            data: _data,
            status: 0
        });

        emit Submission(txId, _target, _value, _data);
    }

    function approveTransaction(uint256 _txId) public {
        require(isOwner(msg.sender), "Only owners can approve");
        require(transactions[_txId].status == 0, "Transaction already executed or canceled");
        require(!approvals[_txId][msg.sender], "Already approved");

        approvals[_txId][msg, sender] = true;
        emit Approval(_txId, msg.sender);
    }

    function executeTransaction(uint256 _txId) public {
        require(isOwner(msg.sender), "Only owners can execute");
        require(transactions[_txId].status == 0, "Transaction already executed or canceled");
        require(countApprovals(_txId) >= threshold, "Insufficient approvals");

        Transaction storage tx = transactions[_txId];
        require(tx.target != address(0), "Cannot send to zero address");

        try address(tx.target).call{value: tx.value}(tx.data) {
            tx.status = 1;
            emit Execution(_txId, tx.target, tx.value, tx.data);
        } catch {
            tx.status = 2;
            emit Execution(_txId, tx.target, tx.value, tx.data);
        }
    }

    function cancelTransaction(uint256 _txId) public {
        require(isOwner(msg.sender), "Only owners can cancel");
        require(transactions[_txId].status == 0, "Transaction already executed or canceled");

        transactions[_txId].status = 2;
        emit Execution(_txId, transactions[_txId].target, transactions[_txId].value, transactions[_txId].data);
    }

    function isOwner(address _addr) internal view returns (bool) {
        for (uint256 i = 0; i < owners.length; i++) {
            if (owners[i] == _addr) {
                return true;
            }
        }
        return false;
    }

    function countApprovals(uint256 _txId) internal view returns (uint256) {
        uint256 count = 0;
        for (uint256 i = 0; i < owners.length; i++) {
            if (approvals[_txId][owners[i]]) {
                count++;
            }
        }
        return count;
    }
}

