        address target = targets[txId];
        uint256 value = values[txId];
        bytes memory data = datas[txId];

        (bool success,) = target.call{value: value}(data);
        require(success, "Transaction failed");

        executed[txId] = true;
        emit TransactionExecuted(txId, target, value, data);
    }

    function isOwner(address account) private view returns (bool) {
        for (uint256 i = 0; i < owners.length; i++) {
            if (owners[i] == account) {
                return true;
            }
        }
        return false;
    }

    function getApprovalsForTransaction(uint256 txId) private view returns (uint256) {
        uint256 approvesReceived = 0;
        for (uint256 i = 0; i < owners.length; i++) {
            if (approvals[txId][owners[i]]) {
                approvesReceived++;
            }
        }
        return approvesReceived;
    }

    // Store transaction details to prevent reentrancy and ensure consistent data during execution
    mapping(uint256 => address) public targets;
    mapping(uint256 => uint256) public values;
    mapping(uint256 => bytes) public datas;

    function setTransactionDetails(uint256 txId, address target, uint256 value, bytes memory data) public {
        require(txId == transactionCount, "Invalid Transaction ID");
        targets[txId] = target;
        values[txId] = value;
        datas[txId] = data;
