// SPDX-License-Identifier: MIT
pragma solidity ^0.8.x;

contract SimpleVoting {
    struct Candidate {
        uint256 voteCount;
    }

    address public admin;
    bool public votingEnded;
    mapping(uint256 => Candidate) public candidates;
    mapping(address => bool) public voters;
    mapping(address => uint256) public voterCandidates;

    event CandidateRegistered(uint256 candidateId);
    event VoteCast(address indexed voter, uint256 candidateId);
    event VotingEnded();

    constructor() {
        admin = msg.sender;
    }

    modifier onlyAdmin() {
        require(msg.sender == admin, "Only admin can call this function");
        _;
    }

    modifier votingNotEnded() {
        require(!votingEnded, "Voting has ended");
        _;
    }

    modifier notVoted(address voter) {
        require(voters[voter] == false, "Already voted");
        _;
    }

    modifier candidateExists(uint256 candidateId) {
        require(candidates[candidateId].voteCount != 0, "Candidate does not exist");
        _;
    }

    function registerCandidate(uint256 candidateId) external onlyAdmin {
        require(candidates[candidateId].voteCount == 0, "Candidate already exists");
        candidates[candidateId] = Candidate(0);
        emit CandidateRegistered(candidateId);
    }

    function vote(uint256 candidateId) external votingNotEnded notVoted(msg.sender) candidateExists(candidateId) {
        voters[msg.sender] = true;
        voterCandidates[msg.sender] = candidateId;
        candidates[candidateId].voteCount++;
        emit VoteCast(msg.sender, candidateId);
    }

    function endVoting() external onlyAdmin {
        require(!votingEnded, "Voting has already ended");
        votingEnded = true;
        emit VotingEnded();
    }

    function getWinningCandidate() external view returns (uint256) {
        require(votingEnded, "Voting has not ended yet");
        uint256 winningCandidateId = 0;
        uint256 highestVoteCount = 0;

        for (uint256 i = 1; i < candidates.length; i++) {
            if (candidates[i].voteCount > highestVoteCount) {
                highestVoteCount = candidates[i].voteCount;
                winningCandidateId = i;
            }
        }

        return winningCandidateId;
    }
}

