// SPDX-License-Identifier: MIT
pragma solidity ^0.8.x;

contract HighestBidAuction {
    address public auctionCreator;
    uint256 public startTime;
    uint256 public endTime;
    uint256 public minimumBid;
    uint256 public highestBid;
    address public highestBidder;
    bool public ended;
    mapping(address => uint256) public bids;

    event NewBid(address indexed bidder, uint256 amount);
    event AuctionEnded();
    event Withdrawal(address indexed withdrawer, uint256 amount);

    constructor(uint256 _startTime, uint256 _endTime, uint256 _minimumBid) {
        auctionCreator = msg.sender;
        startTime = _startTime;
        endTime = _endTime;
        minimumBid = _minimumBid;
    }

    modifier onlyDuringAuction() {
        require(block.timestamp >= startTime && block.timestamp <= endTime, "Auction not active");
        _;
    }

    modifier onlyAfterAuctionEnds() {
        require(ended, "Auction has not ended");
        _;
    }

    function bid() external payable onlyDuringAuction {
        require(msg.value > highestBid, "There already is a higher or equal bid");
        require(msg.value >= minimumBid, "Bid below minimum");

        if (highestBid != 0) {
            payable(highestBidder).transfer(highestBid);
        }

        highestBid = msg.value;
        highestBidder = msg.sender;

        bids[msg.sender] += msg.value;

        emit NewBid(msg.sender, msg.value);
    }

    function endAuction() external onlyAfterAuction {
        require(auctionCreator == msg.sender || block.timestamp > endTime, "Only auction creator can call this before the end time");
        ended = true;
        emit AuctionEnded();
    }

    function withdrawBid() external {
        uint256 amount = bids[msg.sender];
        require(amount > 0, "No bid to withdraw");

        payable(msg.sender).transfer(amount);
        delete bids[msg.sender];

        emit Withdrawal(msg.sender, amount);
    }

    function withdrawWinningBid() external onlyAfterAuction {
        require(auctionCreator == msg.sender, "Only auction creator can withdraw the winning bid");
        require(highestBid > 0, "No winning bid to withdraw");

        payable(auctionCreator).transfer(highestBid);
        highestBid = 0;
        delete bids[highestBidder];

        emit Withdrawal(msg.sender, highestBid);
    }
}

