        require(_startTime > block.timestamp, "Start time must be in the future");
        require(_endTime > _startTime, "End time must be after start time");

        startTime = _startTime;
        endTime = _endTime;
        minBid = _minBid;
    }

    function bid() public payable {
        require(block.timestamp >= startTime && block.timestamp <= endTime, "Auction not active");

        if (msg.value < minBid) revert BidTooLow();
        if (highestBid > 0 && msg.value <= highestBid) revert BidTooLow();

        if (highestBidder != address(0)) {
            bids[highestBidder] += highestBid;
            payable(highestBidder).transfer(highestBid);
        }

        highestBid = msg.value;
        highestBidder = payable(msg.sender);

        emit NewBid(msg.sender, msg.value);
    }

    function withdraw() public {
        require(ended && block.timestamp > endTime + 1 weeks, "Withdrawal not available");
        if (bids[highestBidder] < highestBid) revert AlreadyWithdrawn();

        uint amount = bids[msg.sender];
        delete bids[msg.sender];

        payable(msg.sender).transfer(amount);

        emit Withdrawal(msg.sender, amount);
    }

    function endAuction() public {
        require(block.timestamp > endTime, "Auction not over");

        ended = true;

        if (highestBid > 0) {
            payable(highestBidder).transfer(highestBid);

            emit AuctionEnded(highestBidder, highestBid);
        }
    }
}

