// SPDX-License-Identifier: MIT
pragma solidity ^0.8.17;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract Escrow {
    enum State { Created, Delivered, Released, Refunded, Disputed }

    struct Party {
        address addr;
        uint256 balance;
        bool active;
    }

    mapping (address => Party) public parties;

    State public state;

    modifier onlyActive() {
        require(parties[msg.sender].active, "Only active parties can interact");
        _;
    }

    constructor(address buyer, address seller, address arbiter)
        payable
    {
        require(buyer != address(0), "Buyer address cannot be zero");
        require(seller != address(0), "Seller address cannot be zero");
        require(arbiter != address(0), "Arbiter address cannot be zero");

        parties[buyer] = Party(buyer, msg.value, true);
        parties[seller] = Party(seller, 0, false);
        parties[arbiter] = Party(arbiter, 0, false);

        state = State.Created;
    }

    function deliver() public onlyActive {
        require(state == State.Created, "Only in Created state");
        parties[msg.sender].active = false;

        emit Deliver(msg.sender);
        state = State.Delivered;
    }

    function releasePayment(address to) public onlyActive {
        require(state == State.Delivered, "Only in Delivered state");

        if (parties[to].balance > 0)
            revert("Party has already received payment");

        parties[msg.sender].active = false;

        emit Release(msg.sender, to);
        state = State.Released;
    }

    function refund(address to) public onlyActive {
        require(state == State.Delivered || state == State.Released, "Only in Delivered or Released states");

        if (parties[to].balance > 0)
            revert("Party has already received payment");

        parties[msg.sender].active = false;

        emit Refund(msg.sender, to);
        state = State.Refunded;
    }

    function resolveDispute(address to) public onlyActive {
        require(state == State.Delivered || state == State.Released || state == State.Refunded, "Only in Delivered, Released or Refunded states");

        if (parties[to].balance > 0)
            revert("Party has already received payment");

        parties[msg.sender].active = false;

        emit Dispute(msg.sender, to);
        state = State.Disputed;
    }

    function getBalance(address party) public view returns (uint256) {
        return parties[party].balance;
    }

    function withdraw() public onlyActive {
        require(state == State.Released || state == State.Refunded || state == State.Disputed, "Only in Released, Refunded or Disputed states");

        uint256 balance = parties[msg.sender].balance;

        if (balance > 0) {
            parties[msg.sender].balance = 0;
            payable(msg.sender).transfer(balance);
        }
    }

    event Deliver(address indexed party);
    event Release(address indexed from, address indexed to);
    event Refund(address indexed from, address indexed to);
    event Dispute(address indexed from, address indexed to);
}

