    modifier onlyOwner() {
        require(msg.sender == owner, "OnlyOwner");
        _;
    }

    function registerCandidate(uint256 id, string memory name) external onlyOwner {
        require(id > 0 && candidateCount < 100, "InvalidCandidateIdOrLimitReached");
        require(!candidates[id].isRegistered, "CandidateAlreadyExists");

        candidates[id] = Candidate({
            voteCount: 0,
            isRegistered: true
        });
        emit CandidateRegistered(id, name);
        if (id >= candidateCount) {
            candidateCount = id + 1;
        }
    }

    function withdrawEther() external onlyOwner {
        payable(owner).transfer(address(this).balance);
    }

    function vote(uint256 candidateId) external payable {
        require(block.number > votingEnded, "VotingNotStarted"); // Changed from timestamp to block number
        require(candidates[candidateId].isRegistered && candidates[candidateId].voteCount != 0, "CandidateDoesNotExist");

        address voter = msg.sender;
        require(!hasVoted[voter], "AlreadyVoted");
        require(msg.value > 0, "MustSendEther"); // Added ether requirement

        candidates[candidateId].voteCount++;
        hasVoted[voter] = true;

        emit VoteCast(voter, candidateId);
    }

    function endVoting() external onlyOwner {
        require(block.number <= votingEnded, "VotingAlreadyEnded");
        votingEnded = block.number; // Changed to store block number
        emit VotingEnded();
    }

    function getWinner() external view returns (uint256) {
        require(block.number > votingEnded, "VotingNotEnded"); // Changed from timestamp

        uint256 maxVotes = 0;
        uint256 winnerId = 0;

        for (uint256 i = 1; i < candidateCount; i++) {
            if (candidates[i].isRegistered && candidates[i].voteCount > maxVotes) {
                maxVotes = candidates[i].voteCount;
                winnerId = i;
            }
        }

        return winnerId;
    }

    function getVoteCount(uint256 candidateId) external view returns (uint256) {
        require(candidates[candidateId].isRegistered && candidates[candidateId].voteCount != 0, "CandidateDoesNotExist");
        return candidates[candidateId].voteCount;
    }
}

