            isOwner[_owners[i]] = true;
        }
    }

    modifier onlyOwner() {
        require(isOwner[msg.sender], "Not an owner");
        _;
    }

    function submitTransaction(
        address target,
        uint256 value,
        bytes memory data
    ) external onlyOwner returns (uint256) {
        transactionCount++;
        transactions[transactionCount] = TransactionData(target, value, data);
        emit TransactionSubmitted(transactionCount, target, value, data);
        return transactionCount;
    }

    function approveTransaction(uint256 transactionId) external onlyOwner {
        require(!approvals[transactionId][msg.sender], "Already approved");
        approvals[transactionId][msg.sender] = true;

        uint256 approvalCount = 0;
        for (uint i = 0; i < owners.length; i++) {
            if (approvals[transactionId][owners[i]]) {
                approvalCount++;
            }
        }

        require(approvalCount <= requiredThreshold, "Not enough approvals yet");
        emit Approval(transactionId, msg.sender);
    }

    function executeTransaction(uint256 transactionId) external onlyOwner {
        require(!executed[transactionId], "Already executed");
        require(getApprovalCount(transactionId) >= requiredThreshold, "Insufficient approvals");

        // Checks-Effects-Interactions pattern
        TransactionData memory currentTx = transactions[transactionId];
        require(currentTx.target != address(0), "Invalid transaction target");

        // Update state before external call
        executed[transactionId] = true;

        // Make external call (with proper value and data)
        bool success;
        (success,) = currentTx.target.call{value: currentTx.value}(currentTx.data);

        emit Execution(transactionId, success, currentTx.target, currentTx.value, currentTx.data);
    }

    function getApprovalCount(uint256 transactionId) public view returns (uint256) {
        uint256 count = 0;
        for (uint i = 0; i < owners.length; i++) {
            if (approvals[transactionId][owners[i]]) {
                count++;
            }
        }
        return count;
    }

    function getTransaction(uint256 transactionId)
        public
        view
        returns (
            address target,
            uint256 value,
            bytes memory data
        )
    {
        require(transactionId <= transactionCount, "Invalid transaction ID");
        TransactionData memory currentTx = transactions[transactionId];
        return (currentTx.target, currentTx.value, currentTx.data);
    }
}

