// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract Crowdfunding {
    struct Campaign {
        address creator;
        uint256 goal;
        uint256 deadline;
        bool isActive;
        uint256 totalContributions;
    }

    struct Contribution {
        uint256 amount;
        bool refunded;
    }

    mapping(address => Contribution) public contributions;
    Campaign public campaign;

    address public owner;
    bool public goalReached;

    event CampaignCreated(
        address indexed creator,
        uint256 goal,
        uint256 deadline
    );

    event FundsContributed(
        address indexed contributor,
        uint256 amount
    );

    event FundsWithdrawn(
        address indexed to,
        uint256 amount
    );

    event RefundRequested(
        address indexed contributor,
        uint256 amount
    );

    constructor(
        address _creator,
        uint256 _goal,
        uint256 _deadline
    ) payable {
        require(block.timestamp < _deadline, "Deadline must be in the future");
        require(msg.value > 0, "Initial contribution required");

        owner = _creator;
        campaign.creator = _creator;
        campaign.goal = _goal;
        campaign.deadline = _deadline;
        campaign.isActive = true;
        campaign.totalContributions = msg.value;

        contributions[msg.sender].amount = msg.value;
        contributions[msg.sender].refunded = false;

        emit CampaignCreated(_creator, _goal, _deadline);
    }

    modifier onlyCampaignCreator() {
        require(msg.sender == owner, "Only creator can perform this action");
        _;
    }

    modifier campaignActive() {
        require(block.timestamp < campaign.deadline && campaign.isActive, "Campaign not active");
        _;
    }

    modifier goalNotReached() {
        require(!goalReached, "Goal already reached");
        _;
    }

    function contribute() external payable campaignActive {
        require(msg.value > 0, "Contribution amount must be greater than zero");

        contributions[msg.sender].amount += msg.value;
        campaign.totalContributions += msg.value;

        emit FundsContributed(msg.sender, msg.value);
    }

    function checkGoal() external onlyCampaignCreator {
        require(block.timestamp >= campaign.deadline, "Deadline not reached yet");
        goalReached = (campaign.totalContributions >= campaign.goal);

        if (goalReached) {
            campaign.isActive = false;
        }
    }

    function withdrawFunds() external onlyCampaignCreator {
        require(goalReached && block.timestamp > campaign.deadline, "Goal not reached or deadline not passed");
        require(address(this).balance > 0, "No funds to withdraw");

        payable(owner).transfer(address(this).balance);

        emit FundsWithdrawn(owner, address(this).balance);
    }

    function requestRefund() external goalNotReached {
        Contribution storage contribution = contributions[msg.sender];
        require(!contribution.refunded && contribution.amount > 0, "No refundable amount");

        payable(msg.sender).transfer(contribution.amount);

        contribution.refunded = true;
        campaign.totalContributions -= contribution.amount;

        emit RefundRequested(msg.sender, contribution.amount);
    }

    function getCampaignStatus() external view returns (
        address creator,
        uint256 goal,
        uint256 deadline,
        bool isActive,
        uint256 totalContributions
    ) {
        return (
            campaign.creator,
            campaign.goal,
            campaign.deadline,
            campaign.isActive,
            campaign.totalContributions
        );
    }
}

