pragma solidity ^0.8.20;

contract RoleBasedAccessControl {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN");
    bytes32 public constant MANAGER_ROLE = keccak256("MANAGER");
    bytes32 public constant USER_ROLE = keccak256("USER");

    mapping(bytes32 => mapping(address => bool)) private _roles;
    address private _admin;

    event RoleGranted(bytes32 indexed role, address indexed account);
    event RoleRevoked(bytes32 indexed role, address indexed account);

    constructor() {
        _grantRole(ADMIN_ROLE, msg.sender);
    }

    modifier onlyRole(bytes32 role) {
        require(_hasRole(role, _msgSender()), "RBAC: insufficient access");
        _;
    }

    function _grantRole(bytes32 role, address account) internal {
        require(account != address(0), "RBAC: invalid zero address");
        require(!_hasRole(role, account), "RBAC: already has role");

        _roles[role][account] = true;

        emit RoleGranted(role, account);
    }

    function _revokeRole(bytes32 role, address account) internal {
        require(account != address(0), "RBAC: invalid zero address");
        require(_hasRole(role, account), "RBAC: no such role");

        _roles[role][account] = false;

        emit RoleRevoked(role, account);
    }

    function hasRole(bytes32 role, address account) public view returns (bool) {
        return _roles[role][account];
    }

    function grantRole(bytes32 role, address account) external onlyRole(ADMIN_ROLE) {
        _grantRole(role, account);
    }

    function revokeRole(bytes32 role, address account) external onlyRole(ADMIN_ROLE) {
        _revokeRole(role, account);
    }

    function renounceRole(bytes32 role, address account) external {
        require(account == msg.sender || hasRole(ADMIN_ROLE, msg.sender), "RBAC: insufficient access");
        _revokeRole(role, account);
    }

    function getAdmin() public view returns (address) {
        return _admin;
    }

    function setNewAdmin(address newAdmin) external onlyRole(ADMIN_ROLE) {
        require(newAdmin != address(0), "RBAC: invalid zero address");
        require(!hasRole(ADMIN_ROLE, newAdmin), "RBAC: cannot grant admin to non-zero address");

        _revokeRole(ADMIN_ROLE, _admin);
        _grantRole(ADMIN_ROLE, newAdmin);
    }

    function _msgSender() internal view virtual returns (address) {
        return msg.sender;
    }

    function _hasRole(bytes32 role, address account) internal view returns (bool) {
        return account != address(0) && _roles[role][account];
    }
}

