contract MultiSignatureWallet {
    address[] public owners;
    uint256 public requiredApprovals;
    mapping(uint256 => mapping(address => bool)) public approvals;
    uint256 public transactionCount;

    event Submission(uint256 indexed transactionId, address indexed target, uint256 value, bytes data);
    event Approval(uint256 indexed transactionId, address indexed owner);
    event Execution(uint256 indexed transactionId);

    modifier onlyOwner() {
        require(isOwner(msg.sender), "Not an owner");
        _;
    }

    modifier validThreshold(uint256 _requiredApprovals) {
        require(_requiredApprovals > 0 && _requiredApprovals <= owners.length, "Invalid threshold");
        _;
    }

    constructor(address[] memory _owners, uint256 _requiredApprovals)
        validThreshold(_requiredApprovals)
    {
        owners = _owners;
        requiredApprovals = _requiredApprovals;
    }

    function proposeTransaction(address _target, uint256 _value, bytes memory _data) external onlyOwner returns (uint256) {
        uint256 transactionId = transactionCount++;
        emit Submission(transactionId, _target, _value, _data);
        return transactionId;
    }

    function approveTransaction(uint256 _transactionId) external onlyOwner {
        require(!approvals[_transactionId][msg.sender], "Already approved");
        approvals[_transactionId][msg.sender] = true;
        emit Approval(_transactionId, msg.sender);

        if (getApprovalCount(_transactionId) >= requiredApprovals) {
            executeTransaction(_transactionId);
        }
    }

    function getApprovalCount(uint256 _transactionId) public view returns (uint256 count) {
        for (uint256 i = 0; i < owners.length; i++) {
