pragma solidity ^0.8.0;

contract MultiSigWallet {
    event Submission(uint indexed txId, address target, uint value, bytes data);
    event Approval(uint indexed txId, address indexed owner);
    event Execution(uint indexed txId, address target, uint value, bytes data, bool success, bytes returnData);

    struct Transaction {
        address target;
        uint value;
        bytes data;
        uint numApprovals;
        bool executed;
    }

    address[] public owners;
    uint public threshold;
    uint public transactionCount;
    mapping(uint => Transaction) public transactions;
    mapping(uint => mapping(address => bool)) public approvals;
    mapping(address => bool) public isOwner;
    bool private locked;

    constructor(address[] memory _owners, uint _threshold) {
        require(_owners.length > 0, "Owners cannot be empty");
        require(_threshold <= _owners.length && _threshold > 0, "Invalid threshold");
        for (uint i = 0; i < _owners.length; i++) {
            isOwner[_owners[i]] = true;
        }
        owners = _owners;
        threshold = _threshold;
    }

    function submitTransaction(address _target, uint _value, bytes memory _data) public {
        uint txId = transactionCount;
        transactionCount++;

        transactions[txId] = Transaction({
            target: _target,
            value: _value,
            data: _data,
            numApprovals: 0,
            executed: false
        });

        emit Submission(txId, _target, _value, _data);
    }

    function approveTransaction(uint _txId) public {
        require(isOwner[msg.sender], "Not an owner");
        Transaction storage tx = transactions[_txId];
        require(!tx.executed, "Transaction already executed");
        require(tx.numApprovals < threshold, "Threshold already met");
        require(!approvals[_txId][msg.sender], "Already approved");

        approvals[_txId][msg.sender] = true;
        tx.numApprovals++;

        emit Approval(_txId, msg.sender);
    }

    function executeTransaction(uint _txId) public noReentrancy {
        Transaction storage tx = transactions[_txId];
        require(!tx.executed, "Transaction already executed");
        require(tx.numApprovals >= threshold, "Not enough approvals");

        tx.executed = true;

        (bool success, bytes memory returnData) = tx.target.call{value: tx.value}(tx.data);
        emit Execution(_txId, tx.target, tx.value, tx.data, success, returnData);
    }

    modifier noReentrancy() {
        require(!locked, "Reentrancy guard");
        locked = true;
        _;
        locked = false;
    }
}

