contract Auction {
    event BidPlaced(address indexed bidder, uint256 amount);
    event AuctionEnded(uint256 highestBid);
    event Withdrawn(address indexed recipient, uint256 amount);

    uint256 public startTimestamp;
    uint256 public endTimestamp;
    uint256 public minBid;
    uint256 public highestBid;
    address public highestBidder;
    mapping(address => uint256) public refunds;
    address public owner;

    constructor(uint256 _startTimestamp, uint256 _endTimestamp, uint256 _minBid) {
        require(_endTimestamp > _startTimestamp, "End time must be after start time");
        startTimestamp = _startTimestamp;
        endTimestamp = _endTimestamp;
        minBid = _minBid;
        owner = msg.sender;
    }

    function bid() public payable {
        require(block.timestamp >= startTimestamp && block.timestamp <= endTimestamp, "Auction not open");
        require(msg.value >= minBid, "Bid must be higher than minimum");

        if (highestBidder != address(0)) {
            require(msg.value > highestBid, "Bid must be higher than current highest");
            refunds[highestBidder] += highestBid;
        }

        highestBid = msg.value;
        highestBidder = msg.sender;
        emit BidPlaced(msg.sender, msg.value);
