contract SubscriptionSystem {
    uint256 public immutable subscriptionFee;
    uint256 public immutable duration; // in seconds
    mapping(address => uint256) public expiration;
    uint256 public totalSubscribers;
    uint256 public revenue;

    event SubscriptionCreated(address indexed user, uint256 startTimestamp, uint256 expirationTimestamp);
    event SubscriptionRenewed(address indexed user, uint256 startTimestamp, uint256 expirationTimestamp);

    constructor() {
        subscriptionFee = 1 ether;
        duration = 30 days;
    }

    function subscribe() public payable {
