contract Escrow {
    enum State {Created, Delivered, Released, Refunded, Disputed}

    address public buyer;
    address public seller;
    address public arbiter;
    uint256 public amount;
    State public state;

    event Initialized(address indexed buyer, address indexed seller, address indexed arbiter, uint256 amount);
    event Delivered(address indexed seller);
    event Released(address indexed buyer, address indexed seller);
    event Refunded(address indexed buyer);
    event Disputed(address indexed buyer, string reason);
    event Resolved(address indexed arbiter, address indexed winner, uint256 amountToWinner);

    constructor(address _buyer, address _seller, address _arbiter, uint256 _amount) payable {
        require(_buyer != address(0), "Buyer address cannot be zero");
        require(_seller != address(0), "Seller address cannot be zero");
        require(_arbiter != address(0), "Arbiter address cannot be zero");
        require(_buyer != _seller, "Buyer and seller addresses must be unique");
        require(_buyer != _arbiter, "Buyer and arbiter addresses must be unique");
        require(_seller != _arbiter, "Seller and arbiter addresses must be unique");
        require(msg.value == _amount, "Incorrect amount sent");

        buyer = _buyer;
        seller = _seller;
        arbiter = _arbiter;
        amount = _amount;
        state = State.Created;

        emit Initialized(_buyer, _seller, _arbiter, _amount);
    }

    function deliver() public {
        require(msg.sender == seller, "Only seller can call this function");
        require(state == State.Created, "Contract must be in Created state");

        state = State.Delivered;
        emit Delivered(seller);
    }

    function release() public {
        require(msg.sender == buyer, "Only buyer can call this function");
        require(state == State.Delivered, "Contract must be in Delivered state");

        state = State.Released;
        payable(seller).transfer(amount);
        emit Released(buyer, seller);
    }

    function refund() public {
        require(msg.sender == buyer, "Only buyer can call this function");
        require(state == State.Created, "Contract must be in Created state");

        state = State.Refunded;
        payable(buyer).transfer(amount);
        emit Refunded(buyer);
    }

    function dispute(string memory _reason) public {
        require(msg.sender == buyer, "Only buyer can call this function");
        require(state == State.Delivered, "Contract must be in Delivered state");

        state = State.Disputed;
        emit Disputed(buyer, _reason);
    }

    function resolve(address _winner) public {
        require(msg.sender == arbiter, "Only arbiter can call this function");
        require(state == State.Disputed, "Contract must be in Disputed state");

        uint256 amountToWinner = amount;
        payable(_winner).transfer(amountToWinner);
        state = State.Released; 
        emit Resolved(arbiter, _winner, amountToWinner);
    }

    receive() external payable {}
}

