    event AuctionEnded();
    event Withdrawal(address indexed recipient, uint256 amount);

    modifier onlyDuringAuction() {
        require(block.timestamp >= startTime && block.timestamp <= endTime, "Auction not active");
        _;
    }

    modifier onlyCreator() {
        require(msg.sender == auctionCreator, "Only creator can call this function");
        _;
    }

    constructor(uint256 _startTime, uint256 _endTime, uint256 _minimumBid) {
        auctionCreator = msg.sender;
        startTime = _startTime;
        endTime = _endTime;
        minimumBid = _minimumBid;
    }

    function bid() external payable onlyDuringAuction {
        require(msg.value > highestBid, "There already is a higher or equal bid");
        require(msg.value >= minimumBid, "Bid below minimum");

        if (highestBid != 0) {
            payable(highestBidder).transfer(highestBid);
        }

        highestBid = msg.value;
        highestBidder = msg.sender;

        emit NewBid(msg.sender, msg.value);
    }

    function endAuction() external onlyCreator {
        require(block.number >= block.number + 1, "Auction has not ended");
        require(!ended, "Auction already ended");

        ended = true;
        emit AuctionEnded();
    }

    function withdrawWinningBid() external onlyCreator {
        require(ended, "Auction has not ended");
        require(highestBid != 0, "No bids were made");

        payable(msg.sender).transfer(highestBid);
        highestBid = 0;
        emit Withdrawal(msg.sender, highestBid);
    }

    function withdraw() external onlyCreator {
        uint256 balance = address(this).balance;
        require(balance > 0, "Contract has no balance to withdraw");

        (bool success, ) = msg.sender.call{value: balance}("");
        require(success, "Transfer failed");
    }
}

